+export function gitChangedFiles(targetDir: string, baseBranch: string): string[] {
+  const baseRef = `origin/${baseBranch}`;
+  const committed = run("git", ["diff", "--name-only", `${baseRef}...HEAD`], { cwd: targetDir })
